import React from 'react';

const Sidebar = () => {
  const menuItems = ['Dashboard', 'Simulation', 'Detection', 'Analytics', 'Transactions', 'Settings'];
  return (
    <aside style={{ width: '250px', backgroundColor: '#1e293b', padding: '1.5rem' }}>
      <h1 style={{ fontSize: '1.5rem', fontWeight: 'bold', marginBottom: '2rem' }}>FraudShield</h1>
      <nav>
        <ul>
          {menuItems.map(item => (
            <li key={item} style={{ marginBottom: '1rem' }}>
              <a href="#" style={{ color: item === 'Analytics' ? '#34d399' : 'white', textDecoration: 'none', display: 'block', padding: '0.5rem 1rem', borderRadius: '0.5rem', backgroundColor: item === 'Analytics' ? 'rgba(52, 211, 153, 0.1)' : 'transparent' }}>
                {item}
              </a>
            </li>
          ))}
        </ul>
      </nav>
    </aside>
  );
};

export default Sidebar;
